scwin.initContent = function() {
	var wfmLeft = $p.top().wfm_left.getWindow();
	if (typeof wfmLeft.trvMenu !== "undefined") {
		var windowId = $p.top().wdcMain.getSelectedWindowId();
		var menuNm = $p.top().wdcMain.getWindowLabel(windowId, "window");
		tbxScreenTitle.setLabel(menuNm);
		txtMenuDepth.setValue(comLib.getMenuNavi(windowId));

		// 도움말 파일 다운로드 버튼 보임/숨김
		scwin.setNaviHelpBtn(windowId);
	} else {
		var menuNm = comLib.getParameter("menuNm");
		var menuPath = comLib.getParameter("menuPath");
		if (menuNm != null && menuNm != "") {
			tbxScreenTitle.setLabel(menuNm);
		}
		if (menuPath != null && menuPath != "") {
			txtMenuDepth.setValue(menuPath);
		}
	}
};

scwin.setNaviHelpBtn = function(windowId) {
	var requestData = {};
	requestData.dmaInqireParam = {
		scrinId : windowId,
		intnSysDivCd : comLib.getSysDivCd()
	};
	var option = {
		action : "zz/authmng/retrieveScrin.do",
		reqData : requestData,
		resData : dmaHpc,
		success : "scwin.setNaviHelpBtnCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjaxSync($p, option);
};

scwin.setNaviHelpBtnCallback = function(resBody) {
	if (resBody.message.code != "success") {
		$p.$("#btn_Help").hide();
		$p.$("#btn_HelpMovie").hide();
		$p.$("#btn_law").hide();
	} else {
		if (dmaHpc.get("hpcmFileNm") == "") {
			$p.$("#btn_Help").hide();
		}
		if (dmaHpc.get("hpcmVidoFileNm") == "") {
			$p.$("#btn_HelpMovie").hide();
		}
		if (dmaHpc.get("linkinfo") == "") {
			$p.$("#btn_law").hide();
		}
	}
};

