scwin.btn_Fav_onclick = function() {
	var naviTop = $p.top().wfm_left.getWindow();
	var usrBkMkJson = naviTop.dltLeftMenuList.getMatchedJSON("menuId", naviTop.trvMenu.getSelectedValue(), true, 0, naviTop.dltLeftMenuList.getRowCount());
	if (usrBkMkJson[0].scrinUrl.trim() === "") {
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00057", "즐겨찾기"));
	} else {
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00336"), "scwin.saveUsrBkMkConfirmCallback");
	}
};

scwin.saveUsrBkMkConfirmCallback = function() {
	var naviTop = $p.top().wfm_left.getWindow();
	var usrBkMkJson = naviTop.dltLeftMenuList.getMatchedJSON("menuId", naviTop.trvMenu.getSelectedValue(), true, 0, naviTop.dltLeftMenuList.getRowCount());
	var requestData = {};
	requestData.data = {
		"bkmkMenuId" : usrBkMkJson[0].menuId,
		"menuNm" : usrBkMkJson[0].menuNm,
		"menuLvlNm" : "",
		"scrinUrl" : usrBkMkJson[0].scrinUrl
	};
	var option = {
		action : "sc/usrBkMk/selectUsrBkMk.do",
		reqData : requestData,
		success : "scwin.selectUsrBkMkCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.selectUsrBkMkCallback = function(resBody) {
	var naviTop = $p.top().wfm_left.getWindow();
	if (resBody.data.length == 0) {
		var usrBkMkJson = naviTop.dltLeftMenuList.getMatchedJSON("menuId", naviTop.trvMenu.getSelectedValue(), true, 0, naviTop.dltLeftMenuList.getRowCount());
		var depth = comLib.getMenuNavi($p.top().wdcMain.getSelectedWindowId());
		if (depth != "" && depth.indexOf(" &gt") != -1) {
			depth = depth.substring(0, depth.lastIndexOf(" &gt"));
		}
		var requestData = {};
		requestData.data = {
			"bkmkMenuId" : usrBkMkJson[0].menuId,
			"menuNm" : usrBkMkJson[0].menuNm,
			"menuLvlNm" : depth,
			"scrinUrl" : usrBkMkJson[0].scrinUrl + "," + usrBkMkJson[0].scrinId
		};

		var option = {
			action : "sc/usrBkMk/insertUsrBkMk.do",
			reqData : requestData,
			success : "",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	} else {
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00050", "즐겨찾기가"));
	}
};

scwin.btn_Help_onclick = function() {
	var popupId = dmaHpc.get("hpcmFileNm");
	var options = {
		type : "window", // window, wframePopup
		title : "온라인 도움말",
		width : 1500,
		height : 900,
		modal : false,
		popupParam : {
			data : {
				guideHtml : dmaHpc.get("hpcmFileNm"),
				pageNo : dmaHpc.get("pgeNo")
			}
		}
	};
	// 수도운영에서는 권한관리>화면관리>화면상세>도움말 파일명을 ECSPG+숫자 형태로 입력하고 guide_ecs.xml을 호출하도록 하여 기상, 댐보, 발전종합의 사용자 메뉴얼 팝업과 별도로 띄움
	// 패턴은  ECS + 숫자4자리로 구성
	var fileNm = dmaHpc.get("hpcmFileNm");
	if (/^ECS[\d]{4}$/.test(fileNm) === true) {
		comLib.openPopup($p, popupId, "/ui/ecs/zz/guide/guide_ecs.xml", options);
		return;
	}
	comLib.openPopup($p, popupId, "/ui/ecs/zz/guide/guide.xml&guideHtml=" + dmaHpc.get("hpcmFileNm") + "&pageNo=" + dmaHpc.get("pgeNo"), options);
};

scwin.btn_HelpMovie_onclick = function() {
	var popupId = dmaHpc.get("hpcmVidoFileNm");
	var options = {
		type : "window", // window, wframePopup
		title : "온라인 도움말",
		width : 1500,
		height : 800,
		modal : false,
		popupParam : {
			data : {
				guideVido : dmaHpc.get("hpcmVidoFileNm")
			}
		}
	};
	comLib.openPopup($p, popupId, "/ui/ecs/zz/guide/guideVido.xml", options);
};

/**
 * 규정정보 아이콘 클릭
 */
scwin.btn_law_onclick = function() {
	var naviTop = $p.top().wfm_left.getWindow();
	var popupId ="LAW_" + naviTop.trvMenu.getSelectedValue();
	var options = {
		type : "window", // window, wframePopup
		title : "법령_규정정보",
		width : 1250,
		height : 780,
		modal : false
	};
	comLib.openPopup($p, popupId, comLib.LAW_POP_URL.substring(0, comLib.LAW_POP_URL.indexOf("wq")) + "syslink.jsp?" + dmaHpc.get("linkinfo"), options);
};
